421	        const g = guild();
422	        spiderConfig = g.guildConfig().spider ?? {};
423	
424	        const stacks = g.apparatus<StacksApi>('stacks');
425	        clerk = g.apparatus<ClerkApi>('clerk');
426	        fabricator = g.apparatus<FabricatorApi>('fabricator');
427	
428	        rigsBook = stacks.book<RigDoc>('spider', 'rigs');
429	        sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
430	        writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
431	
432	        // CDC — Phase 1 cascade on rigs book.
433	        // When a rig reaches a terminal state, transition the associated writ.
434	        stacks.watch<RigDoc>(
435	          'spider',
436	          'rigs',
437	          async (event) => {
438	            if (event.type !== 'update') return;
439	
440	            const rig = event.entry;
441	            const prev = event.prev;
442	
443	            // Only act when status changes to a terminal state
444	            if (rig.status === prev.status) return;
445	
446	            if (rig.status === 'completed') {
447	              // Use seal yields as the resolution summary
448	              const sealEngine = rig.engines.find((e) => e.id === 'seal');
449	              const resolution = sealEngine?.yields
450	                ? JSON.stringify(sealEngine.yields)
451	                : 'Rig completed';
452	              await clerk.transition(rig.writId, 'completed', { resolution });
453	            } else if (rig.status === 'failed') {
454	              const failedEngine = rig.engines.find((e) => e.status === 'failed');
455	              const resolution = failedEngine?.error ?? 'Engine failure';
456	              await clerk.transition(rig.writId, 'failed', { resolution });
457	            }
458	          },
459	          { failOnError: true },
